// core/tree/hooks/useTreeEngine.ts

import { useMemo } from 'react';
import {
  createTreeEngine,
  type TreeEngineProps,
} from '../engine/TreeEngine';

/**
 * React hook wrapper for TreeEngine
 *
 * Mirrors PrimeReact internal behavior:
 * - controlled props override internal state
 * - no imperative syncing
 * - engine recreated when inputs change
 */
export function useTreeEngine(props: TreeEngineProps) {
  const engine = useMemo(
    () =>
      createTreeEngine({
        nodes: props.nodes,
        selectionMode: props.selectionMode,
        selectionKeys: props.selectionKeys,
        metaKeySelection: props.metaKeySelection,
        expandedKeys: props.expandedKeys,
        filterValue: props.filterValue,
        filterBy: props.filterBy,
        filterMode: props.filterMode,
        onSelectionChange: props.onSelectionChange,
        onToggle: props.onToggle,
        onExpand: props.onExpand,
        onCollapse: props.onCollapse,
      }),
    [
      props.nodes,
      props.selectionMode,
      props.selectionKeys,
      props.metaKeySelection,
      props.expandedKeys,
      props.filterValue,
      props.filterBy,
      props.filterMode,
      props.onSelectionChange,
      props.onToggle,
      props.onExpand,
      props.onCollapse,
    ]
  );

  return {
    state: engine.state,
    actions: engine.actions,
  };
}
